interface Lesson {
  title: string; content: string; category: string; modality: string;
  keyConcepts: string[]; formulas: { name: string; formula: string; description: string }[];
  difficulty: number;
}

const LESSONS: Lesson[] = [
  { title: "X-ray Production and the X-ray Tube", content: `<h2>Learning Objectives</h2><ul><li>Describe the components of the X-ray tube and their functions</li><li>Explain thermionic emission and electron acceleration</li><li>Differentiate between Bremsstrahlung and Characteristic radiation</li></ul><h2>Key Concepts</h2><p>X-rays are produced when high-speed electrons from the cathode filament strike the tungsten anode target. The cathode consists of a tungsten filament (electron source) within a focusing cup. The anode contains the tungsten target where X-rays are generated.</p><p><strong>Bremsstrahlung (braking) radiation</strong> accounts for ~80-90% of the X-ray beam. It occurs when electrons decelerate near tungsten nuclei, converting kinetic energy to X-ray photons of varying energies.</p><p><strong>Characteristic radiation</strong> occurs when an incident electron ejects an inner-shell electron from tungsten. As outer-shell electrons fill the vacancy, X-ray photons of specific (characteristic) energies are emitted. For tungsten, characteristic X-rays are produced above 69.5 keV (K-shell binding energy).</p><h2>Exam Traps</h2><ul><li>Only ~1% of electron energy becomes X-rays; 99% becomes heat</li><li>Characteristic radiation only occurs above K-shell binding energy</li><li>The filament is the source of electrons, NOT X-rays</li></ul><h2>Memory Aid</h2><p><strong>BREM</strong> = <strong>B</strong>raking <strong>R</strong>adiation <strong>E</strong>nergy <strong>M</strong>ultiple (produces continuous spectrum). <strong>CHAR</strong> = <strong>C</strong>ertain <strong>H</strong>igh-energy <strong>A</strong>tomic <strong>R</strong>adiation (discrete energies).</p>`, category: "Equipment Operation & QC", modality: "Radiography", keyConcepts: ["Thermionic emission", "Bremsstrahlung radiation", "Characteristic radiation", "Cathode/Anode function", "Focusing cup", "Tungsten target", "99% heat 1% X-rays"], formulas: [{ name: "Maximum photon energy", formula: "E_max (keV) = kVp", description: "Maximum X-ray photon energy equals the peak kilovoltage" }], difficulty: 1 },
  { title: "Radiographic Density and mAs", content: `<h2>Learning Objectives</h2><ul><li>Define radiographic density/brightness and its controlling factors</li><li>Apply the mAs-density relationship</li><li>Calculate mAs adjustments for density changes</li></ul><h2>Key Concepts</h2><p><strong>mAs is the PRIMARY controlling factor for image density/brightness.</strong> It controls the quantity of X-ray photons produced. Doubling mAs doubles the number of photons and doubles the receptor exposure.</p><p>The relationship is directly proportional: if you want to see a visible change in density on film, you must change mAs by at least 30% (minimum change rule). In digital imaging, the exposure indicator changes proportionally with mAs.</p><h2>Exam Traps</h2><ul><li>mAs controls QUANTITY, not quality</li><li>In digital imaging, mAs affects noise level (low mAs = more noise) even though brightness can be adjusted post-processing</li><li>The reciprocity law states any mA × time combination yielding the same mAs produces the same exposure</li></ul><h2>Memory Aid</h2><p><strong>mAs = More Atoms Striking</strong> (more photons to the receptor = more density).</p>`, category: "Image Production", modality: "Radiography", keyConcepts: ["mAs controls density", "Direct proportionality", "30% minimum change rule", "Reciprocity law", "Digital: mAs affects noise"], formulas: [{ name: "mAs calculation", formula: "mAs = mA × time (seconds)", description: "Milliampere-seconds equals milliamperage multiplied by exposure time" }, { name: "Density maintenance", formula: "mAs₂ = mAs₁ × (SID₂/SID₁)²", description: "Adjust mAs when changing SID to maintain density" }], difficulty: 1 },
  { title: "Radiographic Contrast and kVp", content: `<h2>Learning Objectives</h2><ul><li>Define radiographic contrast and its controlling factors</li><li>Explain the relationship between kVp and contrast</li><li>Apply the 15% rule</li></ul><h2>Key Concepts</h2><p><strong>kVp is the PRIMARY controlling factor for radiographic contrast.</strong> It controls beam quality (energy/penetrating ability). Higher kVp produces lower contrast (long-scale, more gray shades). Lower kVp produces higher contrast (short-scale, fewer gray shades with more black-and-white).</p><p><strong>The 15% Rule:</strong> Increasing kVp by 15% has the same effect on receptor exposure as doubling the mAs. To maintain density when increasing kVp by 15%, halve the mAs.</p><h2>Exam Traps</h2><ul><li>kVp controls QUALITY (energy), not quantity</li><li>High kVp = MORE Compton scatter = MORE fog = LESS contrast</li><li>Low kVp = MORE photoelectric absorption = LESS scatter = MORE contrast</li><li>15% rule: increase kVp by 15% AND halve mAs to maintain density with reduced contrast</li></ul><h2>Memory Aid</h2><p><strong>kVp = kontrast Varies with Penetration</strong>. High kVp = Low contrast. Low kVp = High contrast. Think "inverse relationship."</p>`, category: "Image Production", modality: "Radiography", keyConcepts: ["kVp controls contrast", "Inverse relationship", "15% rule", "Photoelectric vs Compton", "Short-scale vs long-scale contrast"], formulas: [{ name: "15% rule", formula: "New kVp = Old kVp × 1.15; New mAs = Old mAs / 2", description: "Increasing kVp by 15% doubles exposure; halve mAs to compensate" }], difficulty: 1 },
  { title: "The Inverse Square Law", content: `<h2>Learning Objectives</h2><ul><li>State the inverse square law</li><li>Calculate intensity changes with distance</li><li>Apply the density maintenance formula</li></ul><h2>Key Concepts</h2><p>The <strong>inverse square law</strong> states that radiation intensity is inversely proportional to the square of the distance from the source. If you double the distance, intensity drops to 1/4. If you triple the distance, intensity drops to 1/9.</p><p>The <strong>direct square law (density maintenance formula)</strong> allows you to calculate new mAs when changing SID to maintain the same receptor exposure.</p><h2>Exam Traps</h2><ul><li>Inverse square law: intensity DECREASES with distance</li><li>Direct square law: mAs must INCREASE with distance</li><li>These are reciprocal applications of the same physics</li></ul><h2>Memory Aid</h2><p><strong>Inverse</strong> = intensity goes DOWN as distance goes UP. <strong>Direct</strong> = mAs goes UP as distance goes UP.</p>`, category: "Image Production", modality: "Radiography", keyConcepts: ["Inverse square law", "Direct square law", "Intensity vs distance", "mAs compensation for SID changes"], formulas: [{ name: "Inverse square law", formula: "I₂ = I₁ × (D₁/D₂)²", description: "New intensity = old intensity × (old distance/new distance)²" }, { name: "Direct square law", formula: "mAs₂ = mAs₁ × (SID₂/SID₁)²", description: "New mAs = old mAs × (new SID/old SID)² to maintain density" }], difficulty: 2 },
  { title: "Grids: Construction, Function, and Errors", content: `<h2>Learning Objectives</h2><ul><li>Describe grid construction and purpose</li><li>Identify grid errors and their image appearances</li><li>Calculate grid conversion factors</li></ul><h2>Key Concepts</h2><p>Grids are devices with alternating lead strips and radiolucent interspaces that absorb scatter radiation before it reaches the image receptor. They improve contrast but require increased mAs (patient dose).</p><p><strong>Grid ratio</strong> = height of lead strips / width of interspace. Common ratios: 5:1, 6:1, 8:1, 10:1, 12:1, 16:1. Higher ratio = better scatter cleanup but more patient dose.</p><p><strong>Grid errors:</strong></p><ul><li>Off-center: uniform density loss across entire image</li><li>Off-level (tilted): uniform density loss</li><li>Off-focus (wrong SID): density loss at edges</li><li>Upside-down: good center, severe cutoff at periphery</li></ul><h2>Exam Traps</h2><ul><li>Grid conversion factors: no grid=1, 5:1=2, 6:1=3, 8:1=4, 12:1=5, 16:1=6</li><li>Use grids when body part >10 cm and/or kVp >60-70</li><li>Focused grids have specific focal range</li></ul><h2>Memory Aid</h2><p>Grid errors: <strong>CLFU</strong> — <strong>C</strong>enter (off-center=uniform loss), <strong>L</strong>evel (off-level=uniform loss), <strong>F</strong>ocus (off-focus=edge cutoff), <strong>U</strong>pside-down (center OK, edges cut off).</p>`, category: "Image Production", modality: "Radiography", keyConcepts: ["Grid ratio", "Grid frequency", "Focused vs parallel grids", "Grid conversion factors", "Grid cutoff patterns", "Bucky mechanism"], formulas: [{ name: "Grid ratio", formula: "GR = h/D (height/interspace width)", description: "Grid ratio equals height of lead strips divided by width of interspace" }, { name: "Grid conversion", formula: "mAs₂ = mAs₁ × (GCF₂/GCF₁)", description: "Converting between grid techniques using grid conversion factors" }], difficulty: 2 },
  { title: "Digital Imaging Fundamentals: CR and DR", content: `<h2>Learning Objectives</h2><ul><li>Compare CR and DR systems</li><li>Explain the CR imaging chain</li><li>Differentiate direct and indirect DR conversion</li></ul><h2>Key Concepts</h2><p><strong>Computed Radiography (CR)</strong> uses a photostimulable phosphor (PSP) plate (BaFBr:Eu²⁺). After exposure, the latent image is stored as trapped electrons. A helium-neon laser scans the plate, releasing stored energy as light (PSL), detected by a PMT.</p><p><strong>Direct DR</strong> uses amorphous selenium (a-Se) to directly convert X-rays to electrical signal — no intermediate light step.</p><p><strong>Indirect DR</strong> uses a scintillator (CsI or GOS) to convert X-rays to light, then amorphous silicon (a-Si) photodiodes convert light to electrical signal.</p><h2>Exam Traps</h2><ul><li>CR has lower DQE (15-30%) than DR (45-75%)</li><li>CR plates must be erased (bright light) before reuse</li><li>CsI has needle-like crystals that minimize light spread = better resolution</li><li>DR is faster (no plate handling) but more expensive</li></ul><h2>Memory Aid</h2><p><strong>CR = Cassette Required</strong> (plate in cassette). <strong>DR = Direct/no cassette Required</strong> (integrated detector). Direct DR = <strong>Se</strong>lenium = <strong>Se</strong>lf-converts (no light step).</p>`, category: "Image Production", modality: "Radiography", keyConcepts: ["PSP plate composition", "Laser readout process", "PSL", "Direct vs indirect conversion", "DQE comparison", "a-Se vs CsI/a-Si"], formulas: [], difficulty: 2 },
  { title: "Exposure Indicators and Dose Optimization", content: `<h2>Learning Objectives</h2><ul><li>Interpret exposure indicator values across vendor systems</li><li>Understand the standardized Deviation Index</li><li>Apply ALARA in digital imaging</li></ul><h2>Key Concepts</h2><p>Exposure indicators tell you how much radiation reached the detector. Each vendor has a different system:</p><ul><li><strong>Carestream/Kodak:</strong> EI — higher = more exposure</li><li><strong>Fuji:</strong> S-number — LOWER = more exposure (inverse)</li><li><strong>AAPM Standardized:</strong> EI and Deviation Index (DI). DI=0 is target; positive=overexposure, negative=underexposure</li></ul><p><strong>Dose creep</strong> is the gradual increase in technique because digital's wide dynamic range makes overexposed images still look acceptable. This violates ALARA.</p><h2>Exam Traps</h2><ul><li>Fuji S-number is INVERSE to other systems</li><li>Acceptable DI range: typically ±1 to ±3</li><li>Digital rescaling can mask exposure errors — always check EI</li><li>Overexposure = increased dose with no image quality benefit</li></ul><h2>Memory Aid</h2><p><strong>Fuji is Flipped</strong> — low S = lots of exposure. <strong>DI = 0 = Done It right</strong>.</p>`, category: "Image Production", modality: "Radiography", keyConcepts: ["Vendor EI systems", "Deviation Index", "Dose creep", "ALARA in digital", "Auto-rescaling risks"], formulas: [{ name: "Deviation Index", formula: "DI = 10 × log₁₀(EI_measured / EI_target)", description: "DI = 0 means optimal exposure. Positive = overexposure." }], difficulty: 2 },
  { title: "Radiation Protection: Cardinal Principles", content: `<h2>Learning Objectives</h2><ul><li>Apply the three cardinal principles of radiation protection</li><li>State NCRP dose limits for occupational and public exposure</li><li>Describe shielding requirements</li></ul><h2>Key Concepts</h2><p>The three cardinal principles are: <strong>Time</strong> (minimize time near radiation), <strong>Distance</strong> (maximize distance — inverse square law), <strong>Shielding</strong> (use appropriate barriers).</p><p><strong>Dose Limits (NCRP):</strong></p><ul><li>Occupational whole body: 50 mSv/year</li><li>Occupational cumulative: age × 10 mSv</li><li>Occupational lens of eye: 150 mSv/year</li><li>Occupational skin/extremities: 500 mSv/year</li><li>Embryo/fetus: 5 mSv entire gestation, 0.5 mSv/month</li><li>General public: 1 mSv/year</li></ul><h2>Exam Traps</h2><ul><li>NCRP recommends limits but has NO regulatory authority</li><li>NRC regulates radioactive materials (federal)</li><li>State agencies regulate X-ray equipment</li><li>Distance is the most effective protection method</li></ul><h2>Memory Aid</h2><p>Dose limits: <strong>50-150-500-5-1</strong> = whole body-eye-skin-fetus-public (all in mSv/year except fetus is entire gestation).</p>`, category: "Safety", modality: "Radiography", keyConcepts: ["Time distance shielding", "NCRP dose limits", "Occupational vs public limits", "Embryo/fetus limits", "ALARA", "Regulatory agencies"], formulas: [{ name: "Cumulative dose limit", formula: "Cumulative = Age × 10 mSv", description: "Maximum cumulative occupational dose based on age" }], difficulty: 1 },
  { title: "Radiation Biology: Cell Sensitivity and Effects", content: `<h2>Learning Objectives</h2><ul><li>Explain the Law of Bergonié and Tribondeau</li><li>Classify radiation effects (stochastic vs deterministic)</li><li>Identify the most radiosensitive cells and tissues</li></ul><h2>Key Concepts</h2><p><strong>Law of Bergonié and Tribondeau:</strong> Cells are more radiosensitive when they are: (1) immature/undifferentiated, (2) rapidly dividing (high mitotic rate), (3) have a long mitotic future.</p><p><strong>Most to least radiosensitive cells:</strong> Lymphocytes (exception — mature but highly sensitive) > stem cells > spermatogonia > erythroblasts > intestinal crypt cells > ... > nerve cells > muscle cells.</p><p><strong>Stochastic effects:</strong> No threshold dose, probability increases with dose, all-or-nothing (cancer, genetic effects). <strong>Deterministic effects:</strong> Threshold dose exists, severity increases above threshold (skin erythema, cataracts, sterility).</p><h2>Exam Traps</h2><ul><li>Lymphocytes are the MOST radiosensitive — exception to the law (mature but sensitive)</li><li>Late G2 and M phases of the cell cycle are most radiosensitive</li><li>DNA is the critical target for radiation damage</li><li>LNT model: any dose carries risk (no safe threshold)</li></ul><h2>Memory Aid</h2><p><strong>Stochastic = S = Sometimes</strong> (probability-based, may or may not happen). <strong>Deterministic = D = Definitely</strong> (will happen above threshold, severity increases).</p>`, category: "Safety", modality: "Radiography", keyConcepts: ["Law of Bergonié and Tribondeau", "Radiosensitivity ranking", "Stochastic vs deterministic effects", "Cell cycle sensitivity", "LNT model", "DNA as critical target"], formulas: [], difficulty: 2 },
  { title: "Patient Care: Vital Signs and Assessment", content: `<h2>Learning Objectives</h2><ul><li>State normal ranges for vital signs</li><li>Recognize abnormal vital signs requiring intervention</li><li>Describe proper vital sign assessment techniques</li></ul><h2>Key Concepts</h2><p><strong>Normal Adult Vital Signs:</strong></p><ul><li>Heart rate: 60-100 bpm</li><li>Blood pressure: ~120/80 mmHg (hypertension: >140/90)</li><li>Respiratory rate: 12-20 breaths/min</li><li>Temperature: 97.8-99.1°F (36.5-37.3°C)</li><li>SpO2: 95-100%</li></ul><p><strong>Abnormal findings requiring action:</strong> Bradycardia (<60), Tachycardia (>100), Hypotension (systolic <90), Hypertension (>180/120 = hypertensive crisis), Tachypnea (>20), SpO2 <90%.</p><h2>Exam Traps</h2><ul><li>Always assess patient before, during, and after procedures</li><li>Orthostatic hypotension: BP drops when standing — common in elderly</li><li>Take BP on upper arm, stethoscope over brachial artery</li><li>Use appropriate cuff size (too small = falsely high reading)</li></ul><h2>Memory Aid</h2><p>Vital signs: <strong>60-100-120/80-12-20-98.6-95</strong> = HR-BP-RR-Temp-SpO2 normal values.</p>`, category: "Patient Care & Education", modality: "Radiography", keyConcepts: ["Normal vital sign ranges", "Abnormal findings", "Assessment techniques", "Orthostatic hypotension", "BP cuff sizing"], formulas: [], difficulty: 1 },
  { title: "Contrast Media: Types, Reactions, and Management", content: `<h2>Learning Objectives</h2><ul><li>Classify contrast media types</li><li>Recognize and manage contrast reactions</li><li>Identify risk factors for contrast reactions</li></ul><h2>Key Concepts</h2><p><strong>Positive contrast agents:</strong> Iodinated (IV for CT/IVU) and Barium sulfate (oral/rectal for GI). <strong>Negative contrast:</strong> Air, CO2.</p><p><strong>Iodinated contrast classification:</strong></p><ul><li>HOCM (high-osmolar): ~1500-2000 mOsm/kg — more reactions</li><li>LOCM (low-osmolar): ~500-850 mOsm/kg — fewer reactions</li><li>IOCM (iso-osmolar): ~290 mOsm/kg — fewest reactions</li></ul><p><strong>Reaction severity:</strong></p><ul><li>Mild: nausea, hives, warmth — observe, may give diphenhydramine</li><li>Moderate: diffuse urticaria, bronchospasm, facial edema — epinephrine, diphenhydramine, monitor</li><li>Severe: anaphylaxis, cardiac arrest, laryngeal edema — epinephrine, CPR, code team</li></ul><h2>Exam Traps</h2><ul><li>Barium is CONTRAINDICATED in suspected perforation — causes peritonitis</li><li>Metformin must be withheld 48 hours after iodinated contrast</li><li>Check BUN/creatinine/eGFR before contrast for renal function</li><li>Epinephrine is the FIRST-LINE drug for anaphylaxis</li></ul><h2>Memory Aid</h2><p><strong>Contrast reactions severity: NUB-BAD-SAD</strong>. Mild: Nausea/Urticaria/warmth = Basic. Moderate: Bronchospasm/Angioedema/Dyspnea = Bad. Severe: Shock/Arrest/Death = SAD.</p>`, category: "Patient Care & Education", modality: "Radiography", keyConcepts: ["HOCM vs LOCM vs IOCM", "Reaction classification", "Epinephrine first-line", "Barium contraindications", "Metformin withholding", "Renal function assessment"], formulas: [], difficulty: 2 },
  { title: "Infection Control and Standard Precautions", content: `<h2>Learning Objectives</h2><ul><li>Describe the chain of infection</li><li>Apply Standard Precautions and transmission-based precautions</li><li>Demonstrate proper hand hygiene and PPE use</li></ul><h2>Key Concepts</h2><p><strong>Chain of infection:</strong> Infectious agent → Reservoir → Portal of exit → Mode of transmission → Portal of entry → Susceptible host. Break any link to prevent infection.</p><p><strong>Standard Precautions</strong> apply to ALL patients regardless of diagnosis. Include hand hygiene, PPE as needed, safe injection practices, respiratory hygiene.</p><p><strong>Transmission-based precautions:</strong></p><ul><li>Contact: gown + gloves (MRSA, C. diff)</li><li>Droplet: surgical mask (influenza, pertussis)</li><li>Airborne: N95 respirator + negative pressure room (TB, measles, chickenpox)</li></ul><h2>Exam Traps</h2><ul><li>Hand hygiene is THE most effective infection prevention method</li><li>PPE donning: gown → mask → eye protection → gloves</li><li>PPE removal: gloves → gown → eye protection → mask</li><li>TB requires N95, not surgical mask</li></ul><h2>Memory Aid</h2><p>Chain of infection: <strong>A Rat Exits, Transmits, Enters, Sickens</strong> (Agent-Reservoir-Exit-Transmission-Entry-Susceptible). PPE ON: <strong>G-M-E-G</strong> (gown-mask-eyes-gloves). PPE OFF: <strong>G-G-E-M</strong> (gloves-gown-eyes-mask).</p>`, category: "Patient Care & Education", modality: "Radiography", keyConcepts: ["Chain of infection", "Standard Precautions", "Contact/Droplet/Airborne", "Hand hygiene", "PPE donning and doffing", "N95 vs surgical mask"], formulas: [], difficulty: 1 },
  { title: "Image Quality Factors: Recorded Detail", content: `<h2>Learning Objectives</h2><ul><li>Define recorded detail (spatial resolution) and its controlling factors</li><li>Explain the effects of SID, OID, and focal spot size</li><li>Distinguish between geometric and motion unsharpness</li></ul><h2>Key Concepts</h2><p><strong>Recorded detail (spatial resolution)</strong> is the ability to distinguish fine structures. Measured in line pairs per millimeter (lp/mm).</p><p><strong>Factors improving recorded detail:</strong></p><ul><li>Small focal spot (less penumbra)</li><li>Long SID (more parallel beam)</li><li>Short OID (less magnification)</li><li>Short exposure time (less motion blur)</li></ul><p><strong>Magnification:</strong> MF = SID/SOD = SID/(SID-OID). Magnification always increases geometric unsharpness unless a fractional focal spot is used.</p><h2>Exam Traps</h2><ul><li>The SMALL focal spot is selected for tabletop/detail work</li><li>Intentional magnification requires a FRACTIONAL focal spot (0.1-0.3mm)</li><li>Motion is the MOST common cause of image unsharpness</li><li>Object closest to IR has least magnification and best detail</li></ul><h2>Memory Aid</h2><p><strong>Detail = Small-Long-Short-Fast</strong> = Small focal spot, Long SID, Short OID, Fast exposure time.</p>`, category: "Image Production", modality: "Radiography", keyConcepts: ["Spatial resolution", "Focal spot effect", "SID effect", "OID effect", "Magnification factor", "Motion unsharpness", "Penumbra"], formulas: [{ name: "Magnification factor", formula: "MF = SID / SOD = SID / (SID - OID)", description: "Magnification factor calculation using source-image and source-object distances" }], difficulty: 2 },
  { title: "Automatic Exposure Control (AEC)", content: `<h2>Learning Objectives</h2><ul><li>Explain AEC operation and components</li><li>Select proper ionization chambers for common examinations</li><li>Troubleshoot AEC errors</li></ul><h2>Key Concepts</h2><p>AEC uses ionization chambers (detectors) positioned behind the patient that terminate the exposure when a preset amount of radiation is detected. The technologist selects kVp, the correct chamber(s), and sets a backup time.</p><p><strong>Chamber selection:</strong></p><ul><li>PA chest: both lateral (outside) chambers</li><li>AP abdomen: center chamber</li><li>AP lumbar: center chamber</li><li>Lateral lumbar: center chamber</li></ul><p><strong>Common errors:</strong></p><ul><li>Wrong chamber = incorrect exposure</li><li>Anatomy not covering chamber = overexposure</li><li>Patient too close/far from chamber = incorrect reading</li></ul><h2>Exam Traps</h2><ul><li>PA chest: NEVER use center chamber (spine causes overexposure of lungs)</li><li>AEC automatically compensates for patient size — no manual adjustment needed</li><li>Backup time must be set as safety cutoff (150-200% of expected mAs)</li><li>Each density step changes exposure by ~25-30%</li></ul><h2>Memory Aid</h2><p>PA chest AEC: <strong>Lungs = Laterals</strong> (use the two outside chambers for lung fields).</p>`, category: "Image Production", modality: "Radiography", keyConcepts: ["Ionization chambers", "Chamber selection", "Backup timer", "Density controls", "Common AEC errors", "kVp selection with AEC"], formulas: [], difficulty: 2 },
  { title: "Chest Radiography Techniques and Evaluation", content: `<h2>Learning Objectives</h2><ul><li>Describe proper PA and lateral chest positioning</li><li>Evaluate chest radiographs for quality criteria</li><li>Identify common chest pathology appearances</li></ul><h2>Key Concepts</h2><p><strong>PA Chest:</strong> 72" SID, high kVp (110-125), erect, full inspiration (10+ posterior ribs), scapulae rotated laterally, both lateral AEC chambers.</p><p><strong>Evaluation criteria:</strong></p><ul><li>Rotation: equal clavicle-spinous process distances</li><li>Inspiration: minimum 10 posterior ribs</li><li>Penetration: thoracic vertebrae faintly visible through heart</li><li>Inclusion: from apices to costophrenic angles</li></ul><p><strong>Common pathology appearances:</strong></p><ul><li>Pneumonia: airspace opacity with air bronchograms</li><li>Pneumothorax: absent lung markings, visible pleural line</li><li>CHF: cardiomegaly, cephalization, effusions, edema</li><li>Pleural effusion: costophrenic angle blunting (erect)</li></ul><h2>Exam Traps</h2><ul><li>Left lateral is standard (minimizes cardiac magnification)</li><li>AP portable magnifies the heart — note on image</li><li>Lordotic view for apices (projects clavicles above lungs)</li><li>Decubitus for small effusions or pneumothorax</li></ul><h2>Memory Aid</h2><p>Chest evaluation: <strong>RIPE</strong> = <strong>R</strong>otation (clavicles), <strong>I</strong>nspiration (10 ribs), <strong>P</strong>enetration (vertebrae through heart), <strong>E</strong>xposure/inclusion (apices to CP angles).</p>`, category: "Procedures", modality: "Radiography", keyConcepts: ["72-inch SID", "High kVp technique", "PA vs AP differences", "Evaluation criteria", "Common pathology", "AEC chamber selection"], formulas: [], difficulty: 1 },
  { title: "Upper Extremity Positioning: Wrist and Elbow", content: `<h2>Learning Objectives</h2><ul><li>Position for PA, oblique, and lateral wrist projections</li><li>Position for AP, lateral, and oblique elbow projections</li><li>Identify special projections for specific pathology</li></ul><h2>Key Concepts</h2><p><strong>Wrist:</strong></p><ul><li>PA: hand pronated, CR perpendicular to midcarpal area</li><li>Lateral: ulnar side down, radius/ulna superimposed</li><li>Scaphoid view: ulnar deviation + 10-15° proximal CR angle</li><li>Carpal tunnel (Gaynor-Hart): tangential through carpal canal</li></ul><p><strong>Elbow:</strong></p><ul><li>AP: arm extended, hand supinated, epicondyles equidistant</li><li>Lateral: 90° flexion, thumb up</li><li>External oblique: radial head without ulnar superimposition</li><li>Internal oblique: coronoid process in profile</li></ul><h2>Exam Traps</h2><ul><li>Scaphoid = most commonly fractured carpal bone</li><li>Lateral elbow fat pad signs (sail sign) = occult fracture</li><li>If elbow cannot extend fully: two AP projections (proximal and distal)</li><li>Supinate for AP forearm/elbow; pronate for PA hand/wrist</li></ul><h2>Memory Aid</h2><p>Elbow obliques: <strong>External = Radial</strong> (external rotation shows radial head). <strong>Internal = Coronoid</strong> (internal rotation shows coronoid).</p>`, category: "Procedures", modality: "Radiography", keyConcepts: ["Wrist projections", "Scaphoid view technique", "Elbow projections", "Fat pad signs", "Oblique demonstrations", "Carpal tunnel view"], formulas: [], difficulty: 1 },
  { title: "Lower Extremity Positioning: Ankle and Knee", content: `<h2>Learning Objectives</h2><ul><li>Position for AP, mortise, and lateral ankle projections</li><li>Position for AP, lateral, and tunnel knee projections</li><li>Understand weight-bearing studies</li></ul><h2>Key Concepts</h2><p><strong>Ankle:</strong></p><ul><li>AP: foot dorsiflexed 90°, no rotation</li><li>Mortise: 15-20° internal rotation of entire leg (eliminates tibiofibular overlap)</li><li>Lateral: medial side down, CR to medial malleolus</li></ul><p><strong>Knee:</strong></p><ul><li>AP: 5-7° cephalad to open tibial plateau</li><li>Lateral: 20-30° flexion, 5-7° cephalad, condyles superimposed</li><li>Tunnel (Camp-Coventry): PA axial, knee flexed 40-50°, CR perpendicular to tibia</li><li>Merchant/sunrise: tangential patellar view</li></ul><h2>Exam Traps</h2><ul><li>Mortise view ELIMINATES tibiofibular overlap — 15-20° internal rotation</li><li>5-7° cephalad for AP knee opens the tibial plateau</li><li>Tunnel view demonstrates intercondylar fossa</li><li>Weight-bearing knees: essential for OA evaluation (shows true joint space narrowing)</li></ul><h2>Memory Aid</h2><p>Mortise: <strong>15-20° IN</strong> (internal rotation). AP knee: <strong>5-7° UP</strong> (cephalad). Tunnel: <strong>intercondylar FOSSA</strong>.</p>`, category: "Procedures", modality: "Radiography", keyConcepts: ["Mortise view technique", "Knee CR angles", "Tunnel view", "Merchant view", "Weight-bearing importance", "Tibiofibular overlap"], formulas: [], difficulty: 1 },
  { title: "Spine Positioning: Cervical, Thoracic, and Lumbar", content: `<h2>Learning Objectives</h2><ul><li>Position for standard cervical, thoracic, and lumbar spine projections</li><li>Apply the scotty dog concept to lumbar obliques</li><li>Understand special techniques (breathing, swimmer's lateral)</li></ul><h2>Key Concepts</h2><p><strong>Cervical spine:</strong></p><ul><li>AP axial: 15-20° cephalad to C4</li><li>Lateral: 72" SID, shoulders depressed, must show C7-T1</li><li>Open mouth: demonstrates dens (C1-C2)</li><li>Obliques: demonstrate intervertebral foramina</li></ul><p><strong>Thoracic spine:</strong> AP: CR to T7. Lateral: breathing technique (low mA, long time).</p><p><strong>Lumbar spine:</strong></p><ul><li>AP: knees flexed (flatten lordosis), CR perpendicular to L3</li><li>Lateral: waist supported, L5-S1 spot with 5-8° caudad</li><li>Obliques: 45° rotation for scotty dog/zygapophyseal joints</li></ul><h2>Exam Traps</h2><ul><li>Scotty dog: eye=pedicle, nose=transverse process, ear=superior articular process, front leg=inferior articular process, neck=pars interarticularis</li><li>Collar on scotty dog = spondylolysis (pars defect)</li><li>Swimmer's lateral needed if C7-T1 not visible</li><li>Sacrum: 15° cephalad. Coccyx: 10° caudad (opposite angles!)</li></ul><h2>Memory Aid</h2><p>Scotty dog parts: <strong>Eye-Nose-Ear-Leg-Neck = Pedicle-Transverse Process-SAP-IAP-Pars</strong>. Sacrum/Coccyx: <strong>S=Superior angle (cephalad), C=Caudal angle (caudad)</strong>.</p>`, category: "Procedures", modality: "Radiography", keyConcepts: ["Cervical spine projections", "Breathing technique", "Scotty dog anatomy", "Spondylolysis", "L5-S1 spot lateral", "Sacrum vs coccyx angles"], formulas: [], difficulty: 2 },
  { title: "Skull and Facial Bone Positioning", content: `<h2>Learning Objectives</h2><ul><li>Position for Caldwell, Towne, Waters, and SMV projections</li><li>Identify positioning lines and their significance</li><li>Apply proper sinus radiography technique</li></ul><h2>Key Concepts</h2><p><strong>Positioning lines:</strong> OML (orbitomeatal), IOML (infraorbitomeatal), MML (mentomeatal), AML (acanthiomeatal), GAL (glabelloalveolar). These reference lines determine proper skull positioning.</p><p><strong>Key projections:</strong></p><ul><li>Caldwell: 15° caudad, petrous ridges in lower 1/3 of orbits</li><li>Towne: 30° caudad (OML) or 37° (IOML), demonstrates foramen magnum/dorsum sellae</li><li>Waters: OML 37° to IR, petrous ridges below maxillary sinuses</li><li>SMV: IOML parallel to IR, demonstrates skull base and zygomatic arches</li></ul><h2>Exam Traps</h2><ul><li>Sinuses MUST be imaged erect for air-fluid levels</li><li>Waters 37° angle = petrous ridges BELOW maxillary sinuses</li><li>Caldwell 15° = petrous ridges in LOWER 1/3 of orbits</li><li>Towne: 30° to OML = 37° to IOML (same result)</li></ul><h2>Memory Aid</h2><p><strong>C-T-W = 15-30-37</strong> = Caldwell 15° caudad, Towne 30° caudad, Waters 37° OML-to-IR.</p>`, category: "Procedures", modality: "Radiography", keyConcepts: ["Caldwell Towne Waters SMV", "Positioning lines", "CR angles", "Sinus requirements", "Petrous ridge positions"], formulas: [], difficulty: 2 },
  { title: "Fluoroscopy: Principles and Radiation Protection", content: `<h2>Learning Objectives</h2><ul><li>Describe fluoroscopy system components</li><li>Apply radiation protection measures during fluoroscopy</li><li>Understand image intensifier vs flat panel fluoroscopy</li></ul><h2>Key Concepts</h2><p><strong>Fluoroscopy</strong> provides real-time dynamic imaging using continuous or pulsed X-ray beams. Components include: X-ray tube (under table), image receptor (above patient — II or flat panel), and display monitor.</p><p><strong>Radiation protection in fluoroscopy:</strong></p><ul><li>Maximum tabletop exposure rate: 10 R/min (standard), 20 R/min (high-level)</li><li>Minimum SSD: 15 inches (fixed), 12 inches (mobile C-arm)</li><li>5-minute timer with audible alarm</li><li>Lead apron (0.5 mm Pb) required for all personnel in room</li><li>Pulsed fluoroscopy reduces dose by 50-80%</li></ul><p><strong>Magnification mode</strong> increases dose because ABC increases technique to maintain brightness with smaller input phosphor area.</p><h2>Exam Traps</h2><ul><li>Fluoro tube is UNDER the table (radiation to operator's upper body)</li><li>Last-image hold reduces dose by allowing review without continued fluoroscopy</li><li>C-arm: operator should stand on the image receptor side (away from tube)</li><li>Magnification mode = INCREASED patient dose</li></ul><h2>Memory Aid</h2><p>Fluoro limits: <strong>10-15-5</strong> = 10 R/min max, 15" min SSD, 5-min timer. <strong>Tube Under Table</strong> = scatter goes UP to operator.</p>`, category: "Safety", modality: "Fluoroscopy", keyConcepts: ["Image intensifier operation", "Flat panel fluoroscopy", "Maximum exposure rates", "Minimum SSD", "5-minute timer", "Pulsed fluoroscopy", "Magnification mode dose increase"], formulas: [{ name: "Brightness gain", formula: "BG = Minification gain × Flux gain", description: "Total brightness gain of an image intensifier" }], difficulty: 2 },
  { title: "Personnel Dosimetry and Monitoring", content: `<h2>Learning Objectives</h2><ul><li>Describe types of personnel dosimeters</li><li>Explain proper dosimeter wearing and exchange</li><li>Interpret dosimetry reports</li></ul><h2>Key Concepts</h2><p><strong>Types of dosimeters:</strong></p><ul><li><strong>OSL (Optically Stimulated Luminescence):</strong> Al₂O₃, laser readout, multiple reads possible, most common</li><li><strong>TLD (Thermoluminescent Dosimeter):</strong> LiF, heated for readout, single read only</li><li><strong>Film badge:</strong> film blackening proportional to dose, archival record, largely replaced by OSL/TLD</li><li><strong>Pocket ionization chamber:</strong> real-time reading, self-reading, no permanent record</li></ul><p><strong>Wearing guidelines:</strong></p><ul><li>Collar level (outside apron) for thyroid/lens dose</li><li>Waist level (under apron) for gonadal/fetal dose</li><li>Two badges: collar (outside) + waist (under apron) for fluoroscopy workers</li></ul><h2>Exam Traps</h2><ul><li>NEVER share, intentionally expose, or leave in radiation field</li><li>OSL can be reread; TLD and film cannot</li><li>Exchange period: monthly or quarterly</li><li>Investigation level: >1 mSv/month in most facilities</li></ul><h2>Memory Aid</h2><p>Dosimeters: <strong>OSL = Optical (laser), TLD = Thermal (heat), Film = Film</strong>. Collar = outside apron. Waist = under apron.</p>`, category: "Safety", modality: "Radiography", keyConcepts: ["OSL dosimeter", "TLD dosimeter", "Proper wearing positions", "Two-badge system", "Exchange periods", "Investigation levels"], formulas: [], difficulty: 2 },
  { title: "Patient Transfer and Body Mechanics", content: `<h2>Learning Objectives</h2><ul><li>Demonstrate proper body mechanics for patient transfers</li><li>Apply safe transfer techniques for various patient conditions</li><li>Identify fall prevention strategies</li></ul><h2>Key Concepts</h2><p><strong>Body mechanics principles:</strong></p><ul><li>Wide base of support (feet shoulder-width apart)</li><li>Bend at knees and hips, not the waist</li><li>Keep the load close to your body</li><li>Lift with legs, not back</li><li>Avoid twisting — pivot with feet</li></ul><p><strong>Transfer techniques:</strong></p><ul><li>Wheelchair to table: lock wheelchair, position at 45° angle, support patient</li><li>Stretcher to table: lock stretcher and table, use draw sheet, minimum two people</li><li>Assess patient mobility before transfer</li></ul><p><strong>Fall prevention:</strong> Assess fall risk, keep side rails up, use non-skid footwear, remove obstacles, never leave patient unattended on X-ray table.</p><h2>Exam Traps</h2><ul><li>ALWAYS lock wheels before transfer</li><li>Patient moves toward STRONGER side</li><li>Use a draw sheet for unconscious/immobile patients</li><li>Minimum TWO people for stretcher-to-table transfer</li></ul><h2>Memory Aid</h2><p>Body mechanics: <strong>WIDE-BEND-CLOSE-LEGS-PIVOT</strong> = Wide base, Bend at knees, Close to body, Lift with Legs, Pivot don't twist.</p>`, category: "Patient Care & Education", modality: "Radiography", keyConcepts: ["Body mechanics", "Wide base of support", "Lift with legs", "Transfer techniques", "Fall prevention", "Wheelchair and stretcher transfers"], formulas: [], difficulty: 1 },
  { title: "Quality Control Testing for Radiographic Equipment", content: `<h2>Learning Objectives</h2><ul><li>Describe routine QC tests for X-ray equipment</li><li>State acceptance criteria for kVp, mA, timer, and collimator tests</li><li>Explain monitor QC for digital systems</li></ul><h2>Key Concepts</h2><p><strong>Generator QC tests and tolerances:</strong></p><ul><li>kVp accuracy: ±5% of set value</li><li>Exposure reproducibility: coefficient of variation ≤0.05</li><li>mA linearity: mR/mAs consistent within ±10%</li><li>Timer accuracy: ±5% of set value</li><li>Collimator alignment: ±2% of SID</li><li>CR perpendicularity: ±1 degree</li></ul><p><strong>Additional QC:</strong></p><ul><li>HVL measurement: verifies adequate beam filtration</li><li>Focal spot size: star pattern or slit camera</li><li>Lead apron inspection: fluoroscopic or radiographic annually</li><li>PACS monitor: SMPTE or TG18 test pattern daily</li></ul><h2>Exam Traps</h2><ul><li>Remember: 5% kVp, 5% reproducibility, 10% linearity, 2% collimator</li><li>Annual physicist testing is comprehensive</li><li>Technologist QC: daily monitor checks, weekly reject analysis, monthly phantom</li></ul><h2>Memory Aid</h2><p>QC tolerances: <strong>5-5-10-2</strong> = kVp(5%), reproducibility(5%), linearity(10%), collimator(2% SID).</p>`, category: "Equipment Operation & QC", modality: "Radiography", keyConcepts: ["kVp accuracy ±5%", "Reproducibility ≤0.05 CV", "mA linearity ±10%", "Collimator ±2% SID", "HVL testing", "Monitor QC", "Lead apron inspection"], formulas: [], difficulty: 2 },
  { title: "Pelvis and Hip Radiography", content: `<h2>Learning Objectives</h2><ul><li>Position for AP pelvis, frog-leg lateral, and cross-table lateral hip</li><li>Understand when each projection is appropriate</li><li>Apply gonadal shielding guidelines</li></ul><h2>Key Concepts</h2><p><strong>AP Pelvis:</strong> Legs internally rotated 15-20° (places femoral necks parallel to IR). CR perpendicular midway between ASIS and pubic symphysis. Must demonstrate symmetric iliac wings and obturator foramina.</p><p><strong>Frog-leg lateral (Modified Cleaves):</strong> Hip flexed, knee flexed, thigh abducted 40-45°. Demonstrates femoral head and neck in lateral perspective. <strong>CONTRAINDICATED if fracture suspected.</strong></p><p><strong>Cross-table lateral hip:</strong> Affected leg stays as found. Unaffected leg elevated. Horizontal beam. <strong>Used for suspected fractures — does not move the injured leg.</strong></p><h2>Exam Traps</h2><ul><li>15-20° internal rotation for AP pelvis — do NOT rotate if fracture suspected</li><li>Frog-leg = NEVER for suspected fracture</li><li>Cross-table lateral = ALWAYS for suspected fracture</li><li>Male gonadal shield: over testes without obscuring anatomy</li><li>Female ovarian shield: may obscure pelvic anatomy — use with caution</li></ul><h2>Memory Aid</h2><p><strong>Frog-leg = Fun times (no fracture)</strong>. <strong>Cross-table = Careful (fracture suspected)</strong>. <strong>15-20° IN</strong> for femoral neck visualization.</p>`, category: "Procedures", modality: "Radiography", keyConcepts: ["Internal rotation for AP pelvis", "Frog-leg contraindications", "Cross-table lateral indications", "Gonadal shielding", "Femoral neck visualization"], formulas: [], difficulty: 1 },
  { title: "Abdomen Radiography and Acute Abdomen Series", content: `<h2>Learning Objectives</h2><ul><li>Position for supine, erect, and decubitus abdomen projections</li><li>Understand the acute abdomen series</li><li>Identify common abdominal pathology</li></ul><h2>Key Concepts</h2><p><strong>KUB (AP supine):</strong> CR perpendicular to iliac crests. Must include symphysis pubis to diaphragm. Evaluate bowel gas pattern, calcifications, organ size, psoas shadows.</p><p><strong>Erect abdomen:</strong> Patient erect 5-10 minutes. Must include diaphragm. Demonstrates free air (pneumoperitoneum) and air-fluid levels.</p><p><strong>Left lateral decubitus:</strong> Left side DOWN. Free air rises to RIGHT side (between liver and abdominal wall). Used when patient cannot stand.</p><p><strong>Acute abdomen series:</strong> Supine + erect abdomen ± erect chest (or left lateral decubitus if patient cannot stand).</p><h2>Exam Traps</h2><ul><li>Free air on erect = PERFORATION until proven otherwise</li><li>Left lat decub: left side DOWN, free air rises RIGHT</li><li>3-6-9 rule: small bowel <3 cm, large bowel <6 cm, cecum <9 cm</li><li>Barium CONTRAINDICATED if perforation suspected</li></ul><h2>Memory Aid</h2><p>Decubitus: <strong>Left side DOWN, free air goes RIGHT (UP)</strong>. Erect: <strong>must include the DIAPHRAGM</strong>. 3-6-9 = small-large-cecum normal limits.</p>`, category: "Procedures", modality: "Radiography", keyConcepts: ["KUB positioning", "Erect abdomen technique", "Decubitus technique", "Acute abdomen series", "Pneumoperitoneum detection", "3-6-9 rule"], formulas: [], difficulty: 2 },
  { title: "GI Contrast Studies: Upper GI and Barium Enema", content: `<h2>Learning Objectives</h2><ul><li>Describe upper GI series and barium enema procedures</li><li>Apply proper patient positioning for GI studies</li><li>Understand contrast media selection for GI</li></ul><h2>Key Concepts</h2><p><strong>Upper GI series:</strong> Patient drinks barium. Fluoroscopic evaluation of esophagus (RAO), stomach, and duodenum. RAO demonstrates pylorus, duodenal bulb, and C-loop.</p><p><strong>Barium enema:</strong> Barium administered rectally via enema tip (Sims position for insertion). Double contrast uses barium + air for mucosal detail. Single contrast uses barium only for filling defects.</p><p><strong>Contrast selection:</strong></p><ul><li>Barium sulfate: standard for intact GI tract</li><li>Water-soluble (Gastrografin): used if perforation suspected</li><li>NEVER barium if perforation suspected — causes peritonitis</li></ul><h2>Exam Traps</h2><ul><li>RAO for esophagus and stomach (demonstrates esophagus between spine and heart)</li><li>Sims position for enema tip insertion (left lateral with right knee flexed)</li><li>Trendelenburg fills transverse colon and flexures</li><li>Small bowel follow-through: images every 15-30 min until barium reaches cecum</li></ul><h2>Memory Aid</h2><p>Upper GI positions: <strong>RAO = Right Anterior Oblique = Reveals pylorus And Opening (duodenal bulb)</strong>. Barium enema: <strong>Sims = Side (left) for Insertion</strong>.</p>`, category: "Procedures", modality: "Radiography", keyConcepts: ["Upper GI positions", "Barium vs water-soluble contrast", "Double contrast technique", "Sims position", "SBFT timing", "Barium contraindications"], formulas: [], difficulty: 2 },
  { title: "X-ray Generator Types and Waveforms", content: `<h2>Learning Objectives</h2><ul><li>Compare single-phase, three-phase, and high-frequency generators</li><li>Relate voltage ripple to X-ray output efficiency</li><li>Calculate heat units for different generator types</li></ul><h2>Key Concepts</h2><p><strong>Generator types and ripple:</strong></p><ul><li>Single-phase (full-wave): 100% ripple — least efficient</li><li>Three-phase 6-pulse: ~13-25% ripple</li><li>Three-phase 12-pulse: ~4% ripple</li><li>High-frequency: <1% ripple — most efficient, nearly constant potential</li></ul><p><strong>Impact:</strong> Lower ripple = higher average beam energy = more efficient X-ray production = less exposure time needed for same density.</p><h2>Exam Traps</h2><ul><li>High-frequency generators are standard in modern facilities</li><li>Moving from single-phase to 3-phase requires ~50% less mAs for same density</li><li>Heat unit calculations differ by generator type</li></ul><h2>Memory Aid</h2><p>Ripple: <strong>Single=100%, 6-pulse=13%, 12-pulse=4%, HF=<1%</strong>. Less ripple = more efficient.</p>`, category: "Equipment Operation & QC", modality: "Radiography", keyConcepts: ["Voltage ripple", "Single-phase vs three-phase", "High-frequency generators", "Efficiency comparison", "HU calculations"], formulas: [{ name: "Heat Units (single-phase)", formula: "HU = kVp × mA × time", description: "Heat unit calculation for single-phase generators" }, { name: "Heat Units (3-phase/HF)", formula: "HU = kVp × mA × time × 1.35 (6-pulse) or × 1.41 (12-pulse/HF)", description: "Heat unit calculation with generator correction factor" }], difficulty: 2 },
  { title: "Digital Image Processing: Window and Level", content: `<h2>Learning Objectives</h2><ul><li>Explain window width and window level controls</li><li>Apply appropriate window settings for different anatomy</li><li>Understand look-up tables (LUTs)</li></ul><h2>Key Concepts</h2><p><strong>Window level (WL):</strong> Controls image brightness/density. Increasing WL brightens the image; decreasing darkens it. Set to the average pixel value of the tissue of interest.</p><p><strong>Window width (WW):</strong> Controls image contrast. Narrow window = high contrast (fewer gray levels displayed). Wide window = low contrast (more gray levels displayed).</p><p><strong>Look-up tables (LUTs):</strong> Pre-programmed mapping functions that convert raw detector values to optimal display values for specific body parts and projections.</p><h2>Exam Traps</h2><ul><li>Window level = brightness. Window width = contrast.</li><li>Narrow window = HIGH contrast (useful for bones, subtle differences)</li><li>Wide window = LOW contrast (useful for chest, wide density range)</li><li>LUTs are applied automatically based on exam selection</li><li>Wrong exam selection → wrong LUT → poor image display</li></ul><h2>Memory Aid</h2><p><strong>Level = Light</strong> (brightness). <strong>Width = White-to-black range</strong> (contrast). <strong>Narrow = Noticeable differences</strong> (high contrast). <strong>Wide = Washed out</strong> (low contrast).</p>`, category: "Image Production", modality: "Radiography", keyConcepts: ["Window level controls brightness", "Window width controls contrast", "Narrow vs wide window", "Look-up tables", "Exam selection importance"], formulas: [], difficulty: 1 },
  { title: "Portable and Mobile Radiography", content: `<h2>Learning Objectives</h2><ul><li>Apply proper technique for portable radiography</li><li>Ensure radiation protection for portable examinations</li><li>Troubleshoot common portable radiography challenges</li></ul><h2>Key Concepts</h2><p><strong>Portable radiography</strong> brings the X-ray equipment to the patient (ICU, ER, OR, patient rooms). Key considerations:</p><ul><li>Minimum SID: 40 inches (72 inches preferred for chest when possible)</li><li>Exposure cord: minimum 6 feet long</li><li>Operator must wear lead apron and stand as far as cord allows</li><li>Grid may not be used for all portables (depends on body part thickness)</li></ul><p><strong>Challenges:</strong></p><ul><li>Limited SID increases magnification</li><li>AP projection increases OID for anterior structures (heart magnification)</li><li>Patient positioning limitations</li><li>Multiple lines, tubes, and monitoring equipment in the field</li></ul><h2>Exam Traps</h2><ul><li>6-foot minimum exposure cord length</li><li>Verify all lines/tubes on every portable chest</li><li>AP portable chest magnifies the heart — document on image</li><li>Protect other patients and visitors with distance and shielding</li></ul><h2>Memory Aid</h2><p>Portable: <strong>6-40-Lead-Label</strong> = 6-foot cord, 40" minimum SID, Lead apron required, Label AP Portable.</p>`, category: "Procedures", modality: "Radiography", keyConcepts: ["Minimum SID", "Exposure cord length", "Radiation protection", "AP vs PA magnification", "Line/tube verification", "Grid use decisions"], formulas: [], difficulty: 1 },
  { title: "Medical Ethics and Legal Considerations", content: `<h2>Learning Objectives</h2><ul><li>Apply ethical principles in radiography practice</li><li>Understand legal concepts relevant to radiography</li><li>Describe HIPAA requirements</li></ul><h2>Key Concepts</h2><p><strong>Ethical principles:</strong></p><ul><li>Autonomy: patient's right to make informed decisions</li><li>Beneficence: doing good, acting in patient's best interest</li><li>Non-maleficence: do no harm</li><li>Justice: fair treatment for all patients</li></ul><p><strong>Legal concepts:</strong></p><ul><li>Informed consent: patient voluntarily agrees after being informed of procedure, risks, benefits, alternatives</li><li>Negligence elements: duty, breach, causation, damages</li><li>Respondeat superior: employer liable for employee actions within scope of employment</li><li>Assault: threat of touching. Battery: unauthorized touching.</li></ul><p><strong>HIPAA:</strong> Protects patient health information (PHI). Minimum necessary standard applies. Violations can result in fines and criminal penalties.</p><h2>Exam Traps</h2><ul><li>Performing an exam without consent = battery</li><li>Threatening to perform an exam = assault</li><li>Minors and incapacitated patients: consent from legal guardian</li><li>Emergency exception: implied consent for life-threatening situations</li></ul><h2>Memory Aid</h2><p>Negligence: <strong>D-B-C-D</strong> = Duty, Breach, Causation, Damages. Ethics: <strong>A-B-N-J</strong> = Autonomy, Beneficence, Non-maleficence, Justice.</p>`, category: "Patient Care & Education", modality: "Radiography", keyConcepts: ["Ethical principles", "Informed consent", "Negligence elements", "HIPAA", "Assault vs battery", "Respondeat superior", "Implied consent"], formulas: [], difficulty: 2 },
];

async function seed() {
  let inserted = 0;
  for (const l of LESSONS) {
    const exists = await pool.query(`SELECT id FROM imaging_physics_topics WHERE title = $1`, [l.title]);
    if (exists.rows.length === 0) {
      await pool.query(
        `INSERT INTO imaging_physics_topics (id, title, content, category, modality, key_concepts, formulas, difficulty, status, created_at, updated_at)
         VALUES (gen_random_uuid(), $1, $2, $3, $4, $5, $6::jsonb, $7, 'published', NOW(), NOW())`,
        [l.title, l.content, l.category, l.modality, l.keyConcepts, JSON.stringify(l.formulas), l.difficulty]
      );
      inserted++;
    }
  }
  console.log(`[Lessons] Inserted ${inserted}/${LESSONS.length} USA ARRT structured lessons`);
}

seed().then(() => pool.end()).catch(e => { console.error(e); pool.end(); });
